code = """import json
import pandas as pd
from collections import defaultdict, Counter

# Get the file path from the stored result
file_path = locals()['var_functions.query_db:4']

# Load the full business data from the file
with open(file_path, 'r') as f:
    businesses = json.load(f)

# Find businesses that accept credit cards
credit_card_businesses = []
for business in businesses:
    attrs = business.get('attributes', {})
    if isinstance(attrs, dict) and attrs.get('BusinessAcceptsCreditCards') == 'True':
        credit_card_businesses.append(business)

# Extract categories from description field
def extract_categories(description):
    if not description:
        return []
    desc_lower = description.lower()
    if 'services in' in desc_lower:
        parts = desc_lower.split('services in')
        if len(parts) > 1:
            cats = parts[1].strip()
            if cats.endswith('.'):
                cats = cats[:-1]
            categories = cats.replace(' and ', ',').split(',')
            return [cat.strip() for cat in categories if cat.strip()]
    return []

# Count businesses per category
category_count = Counter()
business_to_categories = {}

for business in credit_card_businesses:
    desc = business.get('description', '')
    categories = extract_categories(desc)
    if categories:
        business_to_categories[business['business_id']] = categories
        for cat in categories:
            category_count[cat] += 1

# Get top category
top_category_data = category_count.most_common(1)[0] if category_count else None

if top_category_data:
    top_category_name, top_category_count = top_category_data
    # Get all business_ids for businesses in this category
    top_category_business_ids = []
    for business_id, categories in business_to_categories.items():
        if top_category_name in categories:
            top_category_business_ids.append(business_id)
    
    result = {
        'top_category': top_category_name,
        'business_count': top_category_count,
        'business_ids': top_category_business_ids
    }
else:
    result = {'error': 'No categories found'}

print('__RESULT__:')
print(json.dumps(result))"""

